#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int *arr = NULL;
        if (n > 0) {
            arr = (int*)malloc(n * sizeof(int));
            for (int i = 0; i < n; ++i) {
                scanf("%d", &arr[i]);
            }
        } else {
            // consume the newline of the empty line if present
            int c = getchar();
            if (c != '\n' && c != EOF) ungetc(c, stdin);
        }
        int target;
        scanf("%d", &target);
        int found = -1;
        for (int i = 0; i < n; ++i) {
            if (arr[i] == target) { found = i; break; }
        }
        printf("%d\n", found);
        free(arr);
    }
    return 0;
}

